import { Component, OnInit } from '@angular/core';
import { RouterOutlet } from '@angular/router';
import { AuthService } from './core/services/auth.service';

/**
 * LearnLoop root shell. Chrome (role-aware nav, brand header) is provided by the
 * authenticated LayoutComponent inside the route tree; public auth pages render
 * standalone. This root only hosts the router outlet and refreshes the current
 * user from the backend on boot.
 * SMOKE_MARKER: LearnLoop
 */
@Component({
  selector: 'app-root',
  standalone: true,
  imports: [RouterOutlet],
  template: `<div data-testid="app-ready"><router-outlet></router-outlet></div>`,
})
export class AppComponent implements OnInit {
  readonly title = 'LearnLoop';

  constructor(private auth: AuthService) {}

  ngOnInit(): void {
    if (this.auth.isLoggedIn() && this.auth.token() && this.auth.token() !== 'demo-token') {
      this.auth.refresh().subscribe({ error: () => {} });
    }
  }
}
